import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/admin/tables
 *
 * Returns all tables ordered by number.
 * Each table includes orderCount: count of unpaid, non-cancelled orders.
 */
export async function GET() {
  try {
    const tables = await prisma.table.findMany({
      orderBy: { number: 'asc' },
      include: {
        orders: {
          where: {
            status: { notIn: ['PAID', 'CANCELLED'] },
          },
          select: { id: true },
        },
      },
    })

    const result = tables.map((t) => ({
      id: t.id,
      number: t.number,
      name: t.name,
      orderCount: t.orders.length,
    }))

    console.log(`[GET /api/admin/tables] Returning ${result.length} tables`)

    return NextResponse.json({ tables: result })
  } catch (error) {
    console.error('[GET /api/admin/tables] Failed:', error)
    return NextResponse.json(
      { error: 'Không thể tải danh sách bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * POST /api/admin/tables
 *
 * Creates a new table.
 * Auto-numbers to max(existing number) + 1.
 * Name auto-generated as "Bàn N".
 */
export async function POST(_request: NextRequest) {
  try {
    // Get the highest existing table number
    const last = await prisma.table.findFirst({
      orderBy: { number: 'desc' },
      select: { number: true },
    })

    const nextNumber = last ? last.number + 1 : 1
    const name = `Bàn ${nextNumber}`

    const table = await prisma.table.create({
      data: { number: nextNumber, name },
    })

    console.log(`[POST /api/admin/tables] Created table #${table.id}: ${table.name} (number=${table.number})`)

    return NextResponse.json(
      {
        id: table.id,
        number: table.number,
        name: table.name,
        orderCount: 0,
      },
      { status: 201 },
    )
  } catch (error) {
    console.error('[POST /api/admin/tables] Failed:', error)
    return NextResponse.json(
      { error: 'Không thể tạo bàn mới. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

type RouteContext = { params: Promise<{ id: string }> }

/**
 * GET /api/admin/tables/[id]
 *
 * Returns a single table with its unpaid order count.
 */
export async function GET(_request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  try {
    const table = await prisma.table.findUnique({
      where: { id },
      include: {
        orders: {
          where: { status: { notIn: ['PAID', 'CANCELLED'] } },
          select: { id: true },
        },
      },
    })

    if (!table) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    console.log(`[GET /api/admin/tables/${id}] Table: ${table.name}, orderCount=${table.orders.length}`)

    return NextResponse.json({
      id: table.id,
      number: table.number,
      name: table.name,
      orderCount: table.orders.length,
    })
  } catch (error) {
    console.error(`[GET /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể tải thông tin bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * PUT /api/admin/tables/[id]
 *
 * Renames a table.
 * Body: { name: string }
 */
export async function PUT(request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json({ error: 'Dữ liệu không hợp lệ.' }, { status: 400 })
  }

  const { name } = body

  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return NextResponse.json({ error: 'Tên bàn không được để trống.' }, { status: 400 })
  }

  const trimmedName = name.trim()
  if (trimmedName.length > 50) {
    return NextResponse.json({ error: 'Tên bàn không được quá 50 ký tự.' }, { status: 400 })
  }

  try {
    const existing = await prisma.table.findUnique({ where: { id } })
    if (!existing) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    const table = await prisma.table.update({
      where: { id },
      data: { name: trimmedName },
    })

    console.log(`[PUT /api/admin/tables/${id}] Renamed to: ${table.name}`)

    return NextResponse.json({
      id: table.id,
      number: table.number,
      name: table.name,
      orderCount: existing.orders?.length ?? 0,
    })
  } catch (error) {
    console.error(`[PUT /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể cập nhật bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * DELETE /api/admin/tables/[id]
 *
 * Deletes a table only if it has no unpaid orders.
 * Guard: checks for orders with status NOT IN ['PAID', 'CANCELLED'].
 */
export async function DELETE(_request: NextRequest, context: RouteContext) {
  const { id: idStr } = await context.params
  const id = parseInt(idStr, 10)

  if (isNaN(id)) {
    return NextResponse.json({ error: 'ID bàn không hợp lệ.' }, { status: 400 })
  }

  try {
    const table = await prisma.table.findUnique({ where: { id } })
    if (!table) {
      return NextResponse.json({ error: 'Bàn không tồn tại.' }, { status: 404 })
    }

    // Deletion guard: check for unpaid orders
    const unpaidOrder = await prisma.order.findFirst({
      where: { tableId: id, status: { notIn: ['PAID', 'CANCELLED'] } },
    })

    if (unpaidOrder) {
      console.log(`[DELETE /api/admin/tables/${id}] Guard triggered: unpaid orders exist`)
      return NextResponse.json(
        { error: 'Bàn đang có đơn chưa thanh toán, không thể xoá.' },
        { status: 409 },
      )
    }

    await prisma.table.delete({ where: { id } })

    console.log(`[DELETE /api/admin/tables/${id}] Deleted table: ${table.name}`)

    return new NextResponse(null, { status: 204 })
  } catch (error) {
    console.error(`[DELETE /api/admin/tables/${id}] Failed:`, error)
    return NextResponse.json(
      { error: 'Không thể xoá bàn. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

import { describe, it, expect, vi, beforeEach } from 'vitest'

// ─── Mock Prisma ────────────────────────────────────────────────────
const mockFindMany = vi.fn()
const mockFindFirst = vi.fn()
const mockCreate = vi.fn()
const mockFindUnique = vi.fn()
const mockUpdate = vi.fn()
const mockDelete = vi.fn()
const mockOrderFindFirst = vi.fn()

vi.mock('@/lib/prisma', () => ({
  prisma: {
    table: {
      findMany: (...args: unknown[]) => mockFindMany(...args),
      findFirst: (...args: unknown[]) => mockFindFirst(...args),
      create: (...args: unknown[]) => mockCreate(...args),
      findUnique: (...args: unknown[]) => mockFindUnique(...args),
      update: (...args: unknown[]) => mockUpdate(...args),
      delete: (...args: unknown[]) => mockDelete(...args),
    },
    order: {
      findFirst: (...args: unknown[]) => mockOrderFindFirst(...args),
    },
  },
}))

// ─── Import route handlers ───────────────────────────────────────────
import { GET, POST } from '../route'
import { GET as GET_ONE, PUT, DELETE } from '../[id]/route'

// ─── Helpers ────────────────────────────────────────────────────────

function makeRequest(url: string, method: string, body?: Record<string, unknown>): Request {
  const init: RequestInit = { method, headers: { 'content-type': 'application/json' } }
  if (body) init.body = JSON.stringify(body)
  return new Request(url, init)
}

function makeContext(id: string | number) {
  return { params: Promise.resolve({ id: String(id) }) }
}

async function json(res: Response) {
  return res.json()
}

// ─── Reset mocks ────────────────────────────────────────────────────
beforeEach(() => {
  vi.clearAllMocks()
})

// =====================================================================
// GET /api/admin/tables
// =====================================================================
describe('GET /api/admin/tables', () => {
  it('returns empty list when no tables exist', async () => {
    mockFindMany.mockResolvedValue([])

    const res = await GET()
    expect(res.status).toBe(200)

    const data = await json(res)
    expect(data.tables).toHaveLength(0)
  })

  it('returns tables ordered by number with orderCount', async () => {
    mockFindMany.mockResolvedValue([
      { id: 1, number: 1, name: 'Bàn 1', orders: [{ id: 10 }, { id: 11 }] },
      { id: 2, number: 2, name: 'Bàn 2', orders: [] },
    ])

    const res = await GET()
    expect(res.status).toBe(200)

    const data = await json(res)
    expect(data.tables).toHaveLength(2)
    expect(data.tables[0]).toEqual({ id: 1, number: 1, name: 'Bàn 1', orderCount: 2 })
    expect(data.tables[1]).toEqual({ id: 2, number: 2, name: 'Bàn 2', orderCount: 0 })
  })

  it('returns 500 on database error', async () => {
    mockFindMany.mockRejectedValue(new Error('DB error'))

    const res = await GET()
    expect(res.status).toBe(500)
  })
})

// =====================================================================
// POST /api/admin/tables
// =====================================================================
describe('POST /api/admin/tables', () => {
  it('creates first table with number=1, name="Bàn 1"', async () => {
    mockFindFirst.mockResolvedValue(null) // no existing tables
    mockCreate.mockResolvedValue({ id: 1, number: 1, name: 'Bàn 1' })

    const req = makeRequest('http://localhost/api/admin/tables', 'POST')
    const res = await POST(req as any)
    expect(res.status).toBe(201)

    const data = await json(res)
    expect(data.number).toBe(1)
    expect(data.name).toBe('Bàn 1')
    expect(data.orderCount).toBe(0)
  })

  it('auto-numbers to max+1', async () => {
    mockFindFirst.mockResolvedValue({ number: 5 })
    mockCreate.mockResolvedValue({ id: 3, number: 6, name: 'Bàn 6' })

    const req = makeRequest('http://localhost/api/admin/tables', 'POST')
    const res = await POST(req as any)
    expect(res.status).toBe(201)

    const data = await json(res)
    expect(data.number).toBe(6)
    expect(data.name).toBe('Bàn 6')
  })

  it('returns 500 on database error', async () => {
    mockFindFirst.mockRejectedValue(new Error('DB error'))

    const req = makeRequest('http://localhost/api/admin/tables', 'POST')
    const res = await POST(req as any)
    expect(res.status).toBe(500)
  })
})

// =====================================================================
// GET /api/admin/tables/[id]
// =====================================================================
describe('GET /api/admin/tables/[id]', () => {
  it('returns single table with orderCount', async () => {
    mockFindUnique.mockResolvedValue({
      id: 1,
      number: 1,
      name: 'Bàn 1',
      orders: [{ id: 10 }, { id: 11 }, { id: 12 }],
    })

    const req = makeRequest('http://localhost/api/admin/tables/1', 'GET')
